import { Routes, Route, BrowserRouter} from 'react-router-dom';

import SignIn from '../pages/SignIn';
import SignUp from '../pages/SignUp';
import Dashboard from '../pages/Dashboard';
import Private from './private';
import ProvedorVariaveisGlobais from '../contexts/variaveisGlobais';
import TelaEventos from '../components/Eventos/telaEventos';

function Rotas(){
    return(   
        <BrowserRouter>
            <Routes>
                <Route path='/' element={ /*<SignIn />*/ <Dashboard><TelaEventos /></Dashboard>} />
                <Route path='/register' element={ <SignUp /> } />
                <Route path='/dashboard' element={ <Private><Dashboard><TelaEventos /></Dashboard></Private> } />
                <Route path='/eventos' element={ <Private><Dashboard><TelaEventos /></Dashboard></Private> } />
                <Route path='/clientes' element={ <Private><Dashboard><TelaEventos /></Dashboard></Private> } />
                <Route path='/brinquedos' element={ <Private><Dashboard><TelaEventos /></Dashboard></Private> } />                
            </Routes>
        </BrowserRouter>     
            
    );
}

export default Rotas;
